import React, { useState, useEffect } from 'react';
import { useNavigate, Navigate } from 'react-router-dom';
import { useAuth } from './hooks/useAuth';

/**
 * Home component for the expense tracker. This component handles
 * displaying the user's transactions, calculating totals and
 * providing a form to add new entries. All data is stored in
 * localStorage, so the app continues to work offline without
 * external dependencies. The design uses Tailwind CSS classes
 * to provide a modern and responsive user interface.
 */
export const Home = () => {
  const { userID, name, photo, isAuth } = useAuth();
  const navigate = useNavigate();

  // Load transactions from localStorage or initialize with an empty array
  const [transactions, setTransactions] = useState(() => {
    const stored = localStorage.getItem('transactions');
    if (stored) {
      try {
        return JSON.parse(stored);
      } catch (e) {
        console.error('Failed to parse transactions from localStorage', e);
      }
    }
    return [];
  });

  // Form fields for new entry
  const [newExp, setNewExp] = useState('');
  const [newPrice, setNewPrice] = useState('');
  const [newType, setNewType] = useState('Expense');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Totals state: balance, income and expense
  const [total, setTotal] = useState({ balance: 0, income: 0, expense: 0 });

  // Recalculate totals whenever the transactions change
  useEffect(() => {
    let income = 0;
    let expense = 0;
    transactions.forEach((t) => {
      const amount = Number(t.price);
      if (t.type === 'Income') {
        income += amount;
      } else {
        expense += amount;
      }
    });
    setTotal({ balance: income - expense, income, expense });
  }, [transactions]);

  // Persist transactions to localStorage on every change
  useEffect(() => {
    localStorage.setItem('transactions', JSON.stringify(transactions));
  }, [transactions]);

  // Add a new transaction to the list
  const handleAdd = () => {
    if (!newExp.trim() || !newPrice) return;
    setIsSubmitting(true);
    setTimeout(() => {
      const newEntry = {
        id: Date.now().toString(),
        userID,
        exp: newExp.trim(),
        price: Number(newPrice),
        type: newType,
        createdAt: new Date().toISOString(),
      };
      setTransactions((prev) => [...prev, newEntry]);
      setNewExp('');
      setNewPrice('');
      setNewType('Expense');
      setIsSubmitting(false);
    }, 300);
  };

  // Delete a transaction by its id
  const handleDelete = (id) => {
    setTransactions((prev) => prev.filter((t) => t.id !== id));
  };

  // Sign the user out by clearing auth info and navigating to login
  const handleSignOut = () => {
    localStorage.removeItem('auth');
    navigate('/');
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && newExp.trim() && newPrice) {
      handleAdd();
    }
  };

  // Guard route: redirect unauthenticated users to the login page
  if (!isAuth) {
    return <Navigate to="/" />;
  }

  return (
    <div className="min-h-screen bg-white">
      {/* Header */}
      <div className="border-b border-gray-200">
        <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-6 flex justify-between items-center">
          <h1 className="text-2xl font-light text-gray-900">Budget Buddy</h1>
          <div className="flex items-center gap-4">
            <span className="text-sm text-gray-600">{name}</span>
            <button
              onClick={handleSignOut}
              className="text-sm font-medium text-gray-600 hover:text-gray-900 transition-colors"
            >
              Sign Out
            </button>
          </div>
        </div>
      </div>

      {/* Main content */}
      <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
        {/* Stats */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-10">
          <div>
            <p className="text-xs uppercase text-gray-500 tracking-wide mb-1">Balance</p>
            <p className={`text-3xl font-light ${total.balance >= 0 ? 'text-gray-900' : 'text-red-600'}`}>
              ₹{Math.abs(total.balance).toLocaleString()}
            </p>
          </div>
          <div>
            <p className="text-xs uppercase text-gray-500 tracking-wide mb-1">Income</p>
            <p className="text-3xl font-light text-gray-900">₹{total.income.toLocaleString()}</p>
          </div>
          <div>
            <p className="text-xs uppercase text-gray-500 tracking-wide mb-1">Expense</p>
            <p className="text-3xl font-light text-red-600">₹{total.expense.toLocaleString()}</p>
          </div>
        </div>

        {/* Content grid */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
          {/* Add entry form */}
          <div>
            <h2 className="text-lg font-light text-gray-900 mb-6">Add Entry</h2>
            <div className="space-y-4">
              <div>
                <label className="block text-xs font-medium text-gray-700 mb-2 uppercase tracking-wide">
                  Description
                </label>
                <input
                  type="text"
                  placeholder="Groceries"
                  value={newExp}
                  onChange={(e) => setNewExp(e.target.value)}
                  onKeyPress={handleKeyPress}
                  disabled={isSubmitting}
                  className="w-full px-4 py-2 border border-gray-300 text-sm focus:outline-none focus:ring-1 focus:ring-gray-900 focus:border-transparent transition-all disabled:opacity-50 disabled:cursor-not-allowed"
                />
              </div>

              <div>
                <label className="block text-xs font-medium text-gray-700 mb-2 uppercase tracking-wide">
                  Amount
                </label>
                <input
                  type="number"
                  placeholder="0.00"
                  value={newPrice}
                  onChange={(e) => setNewPrice(e.target.value)}
                  onKeyPress={handleKeyPress}
                  disabled={isSubmitting}
                  className="w-full px-4 py-2 border border-gray-300 text-sm focus:outline-none focus:ring-1 focus:ring-gray-900 focus:border-transparent transition-all disabled:opacity-50 disabled:cursor-not-allowed"
                />
              </div>

              <div>
                <label className="block text-xs font-medium text-gray-700 mb-3 uppercase tracking-wide">
                  Type
                </label>
                <div className="flex gap-3">
                  <label className="flex-1">
                    <input
                      type="radio"
                      name="type"
                      value="Expense"
                      checked={newType === 'Expense'}
                      onChange={(e) => setNewType(e.target.value)}
                      className="sr-only"
                    />
                    <div className={`px-4 py-2 text-sm text-center cursor-pointer border transition-colors ${
                      newType === 'Expense' 
                        ? 'border-gray-900 bg-gray-900 text-white' 
                        : 'border-gray-300 text-gray-700 hover:border-gray-900'
                    }`}>
                      Expense
                    </div>
                  </label>
                  <label className="flex-1">
                    <input
                      type="radio"
                      name="type"
                      value="Income"
                      checked={newType === 'Income'}
                      onChange={(e) => setNewType(e.target.value)}
                      className="sr-only"
                    />
                    <div className={`px-4 py-2 text-sm text-center cursor-pointer border transition-colors ${
                      newType === 'Income' 
                        ? 'border-gray-900 bg-gray-900 text-white' 
                        : 'border-gray-300 text-gray-700 hover:border-gray-900'
                    }`}>
                      Income
                    </div>
                  </label>
                </div>
              </div>

              <button
                onClick={handleAdd}
                disabled={isSubmitting || !newExp.trim() || !newPrice}
                className="w-full bg-gray-900 hover:bg-gray-800 disabled:bg-gray-400 disabled:cursor-not-allowed text-white py-2 px-4 text-sm font-medium transition-colors"
              >
                {isSubmitting ? 'Adding...' : 'Add Entry'}
              </button>
            </div>
          </div>

          {/* Transactions list */}
          <div className="lg:col-span-2">
            <h2 className="text-lg font-light text-gray-900 mb-6">Transactions</h2>
            {transactions.length === 0 ? (
              <p className="text-sm text-gray-500">No transactions yet</p>
            ) : (
              <div className="space-y-2 max-h-96 overflow-y-auto">
                {transactions.map((tran) => (
                  <div key={tran.id} className="flex justify-between items-center py-3 px-4 border border-gray-200 hover:border-gray-300 transition-colors">
                    <div className="flex-1">
                      <p className="text-sm text-gray-900">{tran.exp}</p>
                      <p className="text-xs text-gray-500 mt-1">
                        {new Date(tran.createdAt).toLocaleDateString('en-IN')}
                      </p>
                    </div>
                    <div className="flex items-center gap-4">
                      <span className={`text-sm font-medium ${tran.type === 'Expense' ? 'text-red-600' : 'text-gray-900'}`}>
                        {tran.type === 'Expense' ? '−' : '+'}₹{Number(tran.price).toLocaleString()}
                      </span>
                      <button
                        onClick={() => handleDelete(tran.id)}
                        className="text-gray-400 hover:text-red-600 text-xs font-medium transition-colors"
                      >
                        Remove
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};
